const fs = require('fs');
const filePath = ($json.body && $json.body.path) || ($json.path) || '';
if (!filePath) return [{ json: { output: '❌ Falta el parámetro path' } }];
try {
  const content = fs.readFileSync(filePath, 'utf8');
  const truncated = content.substring(0, 10000);
  const suffix = content.length > 10000 ? '\n\n[... truncado a 10000 chars ...]' : '';
  return [{ json: { output: '📄 ' + filePath + ':\n\n' + truncated + suffix } }];
} catch(e) {
  return [{ json: { output: '❌ Error leyendo archivo: ' + e.message } }];
}
